bool bplmn_id_info_nr_item_ext_ies_o::is_id_valid(const uint32_t& id)
{
  static const uint32_t names[] = {233, 220};
  for (const auto& o : names) {
    if (o == id) {
      return true;
    }
  }
  return false;
}
