        varlength_field_unpack_guard varlen_scope(bref, true);
        HANDLE_CODE(
            unpack_integer(source_ng_ra_nnode_ue_xn_ap_id, bref, (uint64_t)0u, (uint64_t)4294967295u, false, true));
