OCUDUASN_CODE ran_multicast_group_paging_ies_container::unpack(cbit_ref& bref)
{
  uint32_t nof_ies = 0;
  unpack_length(nof_ies, bref, 0u, 65535u, true);

  uint32_t nof_mandatory_ies = 3;

  for (; nof_ies > 0; --nof_ies) {
    uint32_t id;
    HANDLE_CODE(unpack_integer(id, bref, (uint32_t)0u, (uint32_t)65535u, false, true));
    crit_e crit;
    HANDLE_CODE(crit.unpack(bref));

    switch (id) {
      case 269: {
        nof_mandatory_ies--;
        varlength_field_unpack_guard varlen_scope(bref, true);
        HANDLE_CODE(mbs_session_id.unpack(bref));
        break;
      }
      case 270: {
        nof_mandatory_ies--;
        varlength_field_unpack_guard varlen_scope(bref, true);
        HANDLE_CODE(unpack_dyn_seq_of(ue_id_idx_list_mbs_group_paging, bref, 1, 4096, true));
        break;
      }
      case 271: {
        nof_mandatory_ies--;
        varlength_field_unpack_guard varlen_scope(bref, true);
        HANDLE_CODE(multicast_ran_paging_area.unpack(bref));
        break;
      }
      default:
        asn1::log_error("Unpacked object ID={} is not recognized\n", id);
        return OCUDUASN_ERROR_DECODE_FAIL;
    }
  }
  if (nof_mandatory_ies > 0) {
    asn1::log_error("Mandatory fields are missing\n");

    return OCUDUASN_ERROR_DECODE_FAIL;
  }
  return OCUDUASN_SUCCESS;
}
void ran_multicast_group_paging_ies_container::to_json(json_writer& j) const
{
  j.start_obj();
  j.write_int("id", 269);
  j.write_str("criticality", "reject");
  mbs_session_id.to_json(j);
  j.write_int("id", 270);
  j.write_str("criticality", "reject");
  j.start_array("Value");
  for (const auto& e1 : ue_id_idx_list_mbs_group_paging) {
    e1.to_json(j);
  }
  j.end_array();
  j.write_int("id", 271);
  j.write_str("criticality", "reject");
  multicast_ran_paging_area.to_json(j);
  j.end_obj();
}

