OCUDUASN_CODE ran_paging_ies_container::pack(bit_ref& bref) const
{
  uint32_t nof_ies = 4;
  nof_ies += paging_prio_present ? 1 : 0;
  nof_ies += assist_data_for_ran_paging_present ? 1 : 0;
  nof_ies += ue_radio_cap_for_paging_present ? 1 : 0;
  nof_ies += extended_ue_id_idx_value_present ? 1 : 0;
  nof_ies += eutra_paginge_drx_info_present ? 1 : 0;
  nof_ies += ue_specific_drx_present ? 1 : 0;
  nof_ies += nr_paginge_drx_info_present ? 1 : 0;
  nof_ies += nr_paginge_drx_infofor_rrc_inactive_present ? 1 : 0;
  nof_ies += paging_cause_present ? 1 : 0;
  nof_ies += pe_ip_sassist_info_present ? 1 : 0;
  pack_length(bref, nof_ies, 0u, 65535u, true);

  {
    HANDLE_CODE(pack_integer(bref, (uint32_t)89, (uint32_t)0u, (uint32_t)65535u, false, true));
    HANDLE_CODE(crit_e{crit_e::reject}.pack(bref));
    varlength_field_pack_guard varlen_scope(bref, true);
    HANDLE_CODE(ue_id_idx_value.pack(bref));
  }
  {
    HANDLE_CODE(pack_integer(bref, (uint32_t)90, (uint32_t)0u, (uint32_t)65535u, false, true));
    HANDLE_CODE(crit_e{crit_e::ignore}.pack(bref));
    varlength_field_pack_guard varlen_scope(bref, true);
    HANDLE_CODE(ue_ran_paging_id.pack(bref));
  }
  {
    HANDLE_CODE(pack_integer(bref, (uint32_t)31, (uint32_t)0u, (uint32_t)65535u, false, true));
    HANDLE_CODE(crit_e{crit_e::ignore}.pack(bref));
    varlength_field_pack_guard varlen_scope(bref, true);
    HANDLE_CODE(paging_drx.pack(bref));
  }
  {
    HANDLE_CODE(pack_integer(bref, (uint32_t)52, (uint32_t)0u, (uint32_t)65535u, false, true));
    HANDLE_CODE(crit_e{crit_e::reject}.pack(bref));
    varlength_field_pack_guard varlen_scope(bref, true);
    HANDLE_CODE(ran_paging_area.pack(bref));
  }
  if (paging_prio_present) {
    HANDLE_CODE(pack_integer(bref, (uint32_t)53, (uint32_t)0u, (uint32_t)65535u, false, true));
    HANDLE_CODE(crit_e{crit_e::ignore}.pack(bref));
    varlength_field_pack_guard varlen_scope(bref, true);
    HANDLE_CODE(paging_prio.pack(bref));
  }
  if (assist_data_for_ran_paging_present) {
    HANDLE_CODE(pack_integer(bref, (uint32_t)5, (uint32_t)0u, (uint32_t)65535u, false, true));
    HANDLE_CODE(crit_e{crit_e::ignore}.pack(bref));
    varlength_field_pack_guard varlen_scope(bref, true);
    HANDLE_CODE(assist_data_for_ran_paging.pack(bref));
  }
  if (ue_radio_cap_for_paging_present) {
    HANDLE_CODE(pack_integer(bref, (uint32_t)122, (uint32_t)0u, (uint32_t)65535u, false, true));
    HANDLE_CODE(crit_e{crit_e::ignore}.pack(bref));
    varlength_field_pack_guard varlen_scope(bref, true);
    HANDLE_CODE(ue_radio_cap_for_paging.pack(bref));
  }
  if (extended_ue_id_idx_value_present) {
    HANDLE_CODE(pack_integer(bref, (uint32_t)244, (uint32_t)0u, (uint32_t)65535u, false, true));
    HANDLE_CODE(crit_e{crit_e::ignore}.pack(bref));
    varlength_field_pack_guard varlen_scope(bref, true);
    HANDLE_CODE(extended_ue_id_idx_value.pack(bref));
  }
  if (eutra_paginge_drx_info_present) {
    HANDLE_CODE(pack_integer(bref, (uint32_t)245, (uint32_t)0u, (uint32_t)65535u, false, true));
    HANDLE_CODE(crit_e{crit_e::ignore}.pack(bref));
    varlength_field_pack_guard varlen_scope(bref, true);
    HANDLE_CODE(eutra_paginge_drx_info.pack(bref));
  }
  if (ue_specific_drx_present) {
    HANDLE_CODE(pack_integer(bref, (uint32_t)248, (uint32_t)0u, (uint32_t)65535u, false, true));
    HANDLE_CODE(crit_e{crit_e::ignore}.pack(bref));
    varlength_field_pack_guard varlen_scope(bref, true);
    HANDLE_CODE(ue_specific_drx.pack(bref));
  }
  if (nr_paginge_drx_info_present) {
    HANDLE_CODE(pack_integer(bref, (uint32_t)348, (uint32_t)0u, (uint32_t)65535u, false, true));
    HANDLE_CODE(crit_e{crit_e::ignore}.pack(bref));
    varlength_field_pack_guard varlen_scope(bref, true);
    HANDLE_CODE(nr_paginge_drx_info.pack(bref));
  }
  if (nr_paginge_drx_infofor_rrc_inactive_present) {
    HANDLE_CODE(pack_integer(bref, (uint32_t)349, (uint32_t)0u, (uint32_t)65535u, false, true));
    HANDLE_CODE(crit_e{crit_e::ignore}.pack(bref));
    varlength_field_pack_guard varlen_scope(bref, true);
    HANDLE_CODE(nr_paginge_drx_infofor_rrc_inactive.pack(bref));
  }
  if (paging_cause_present) {
    HANDLE_CODE(pack_integer(bref, (uint32_t)356, (uint32_t)0u, (uint32_t)65535u, false, true));
    HANDLE_CODE(crit_e{crit_e::ignore}.pack(bref));
    varlength_field_pack_guard varlen_scope(bref, true);
    HANDLE_CODE(paging_cause.pack(bref));
  }
  if (pe_ip_sassist_info_present) {
    HANDLE_CODE(pack_integer(bref, (uint32_t)357, (uint32_t)0u, (uint32_t)65535u, false, true));
    HANDLE_CODE(crit_e{crit_e::ignore}.pack(bref));
    varlength_field_pack_guard varlen_scope(bref, true);
    HANDLE_CODE(pe_ip_sassist_info.pack(bref));
  }

  return OCUDUASN_SUCCESS;
}
OCUDUASN_CODE ran_paging_ies_container::unpack(cbit_ref& bref)
{
  uint32_t nof_ies = 0;
  unpack_length(nof_ies, bref, 0u, 65535u, true);

  uint32_t nof_mandatory_ies = 4;

  for (; nof_ies > 0; --nof_ies) {
    uint32_t id;
    HANDLE_CODE(unpack_integer(id, bref, (uint32_t)0u, (uint32_t)65535u, false, true));
    crit_e crit;
    HANDLE_CODE(crit.unpack(bref));

    switch (id) {
      case 89: {
        nof_mandatory_ies--;
        varlength_field_unpack_guard varlen_scope(bref, true);
        HANDLE_CODE(ue_id_idx_value.unpack(bref));
        break;
      }
      case 90: {
        nof_mandatory_ies--;
        varlength_field_unpack_guard varlen_scope(bref, true);
        HANDLE_CODE(ue_ran_paging_id.unpack(bref));
        break;
      }
      case 31: {
        nof_mandatory_ies--;
        varlength_field_unpack_guard varlen_scope(bref, true);
        HANDLE_CODE(paging_drx.unpack(bref));
        break;
      }
      case 52: {
        nof_mandatory_ies--;
        varlength_field_unpack_guard varlen_scope(bref, true);
        HANDLE_CODE(ran_paging_area.unpack(bref));
        break;
      }
      case 53: {
        paging_prio_present = true;
        varlength_field_unpack_guard varlen_scope(bref, true);
        HANDLE_CODE(paging_prio.unpack(bref));
        break;
      }
      case 5: {
        assist_data_for_ran_paging_present = true;
        varlength_field_unpack_guard varlen_scope(bref, true);
        HANDLE_CODE(assist_data_for_ran_paging.unpack(bref));
        break;
      }
      case 122: {
        ue_radio_cap_for_paging_present = true;
        varlength_field_unpack_guard varlen_scope(bref, true);
        HANDLE_CODE(ue_radio_cap_for_paging.unpack(bref));
        break;
      }
      case 244: {
        extended_ue_id_idx_value_present = true;
        varlength_field_unpack_guard varlen_scope(bref, true);
        HANDLE_CODE(extended_ue_id_idx_value.unpack(bref));
        break;
      }
      case 245: {
        eutra_paginge_drx_info_present = true;
        varlength_field_unpack_guard varlen_scope(bref, true);
        HANDLE_CODE(eutra_paginge_drx_info.unpack(bref));
        break;
      }
      case 248: {
        ue_specific_drx_present = true;
        varlength_field_unpack_guard varlen_scope(bref, true);
        HANDLE_CODE(ue_specific_drx.unpack(bref));
        break;
      }
      case 348: {
        nr_paginge_drx_info_present = true;
        varlength_field_unpack_guard varlen_scope(bref, true);
        HANDLE_CODE(nr_paginge_drx_info.unpack(bref));
        break;
      }
      case 349: {
        nr_paginge_drx_infofor_rrc_inactive_present = true;
        varlength_field_unpack_guard varlen_scope(bref, true);
        HANDLE_CODE(nr_paginge_drx_infofor_rrc_inactive.unpack(bref));
        break;
      }
      case 356: {
        paging_cause_present = true;
        varlength_field_unpack_guard varlen_scope(bref, true);
        HANDLE_CODE(paging_cause.unpack(bref));
        break;
      }
      case 357: {
        pe_ip_sassist_info_present = true;
        varlength_field_unpack_guard varlen_scope(bref, true);
        HANDLE_CODE(pe_ip_sassist_info.unpack(bref));
        break;
      }
      default:
        asn1::log_error("Unpacked object ID={} is not recognized\n", id);
        return OCUDUASN_ERROR_DECODE_FAIL;
    }
  }
  if (nof_mandatory_ies > 0) {
    asn1::log_error("Mandatory fields are missing\n");

    return OCUDUASN_ERROR_DECODE_FAIL;
  }
  return OCUDUASN_SUCCESS;
}
void ran_paging_ies_container::to_json(json_writer& j) const
{
  j.start_obj();
  j.write_int("id", 89);
  j.write_str("criticality", "reject");
  ue_id_idx_value.to_json(j);
  j.write_int("id", 90);
  j.write_str("criticality", "ignore");
  ue_ran_paging_id.to_json(j);
  j.write_int("id", 31);
  j.write_str("criticality", "ignore");
  j.write_str("Value", paging_drx.to_string());
  j.write_int("id", 52);
  j.write_str("criticality", "reject");
  ran_paging_area.to_json(j);
  if (paging_prio_present) {
    j.write_int("id", 53);
    j.write_str("criticality", "ignore");
    j.write_str("Value", paging_prio.to_string());
  }
  if (assist_data_for_ran_paging_present) {
    j.write_int("id", 5);
    j.write_str("criticality", "ignore");
    assist_data_for_ran_paging.to_json(j);
  }
  if (ue_radio_cap_for_paging_present) {
    j.write_int("id", 122);
    j.write_str("criticality", "ignore");
    ue_radio_cap_for_paging.to_json(j);
  }
  if (extended_ue_id_idx_value_present) {
    j.write_int("id", 244);
    j.write_str("criticality", "ignore");
    j.write_str("Value", extended_ue_id_idx_value.to_string());
  }
  if (eutra_paginge_drx_info_present) {
    j.write_int("id", 245);
    j.write_str("criticality", "ignore");
    eutra_paginge_drx_info.to_json(j);
  }
  if (ue_specific_drx_present) {
    j.write_int("id", 248);
    j.write_str("criticality", "ignore");
    j.write_str("Value", ue_specific_drx.to_string());
  }
  if (nr_paginge_drx_info_present) {
    j.write_int("id", 348);
    j.write_str("criticality", "ignore");
    nr_paginge_drx_info.to_json(j);
  }
  if (nr_paginge_drx_infofor_rrc_inactive_present) {
    j.write_int("id", 349);
    j.write_str("criticality", "ignore");
    nr_paginge_drx_infofor_rrc_inactive.to_json(j);
  }
  if (paging_cause_present) {
    j.write_int("id", 356);
    j.write_str("criticality", "ignore");
    j.write_str("Value", "voice");
  }
  if (pe_ip_sassist_info_present) {
    j.write_int("id", 357);
    j.write_str("criticality", "ignore");
    pe_ip_sassist_info.to_json(j);
  }
  j.end_obj();
}

// SplitSRB-RRCTransfer ::= SEQUENCE
OCUDUASN_CODE split_srb_rrc_transfer_s::pack(bit_ref& bref) const
{
  bref.pack(ext, 1);
  HANDLE_CODE(bref.pack(rrc_container.size() > 0, 1));
  HANDLE_CODE(bref.pack(delivery_status_present, 1));
  HANDLE_CODE(bref.pack(ie_exts_present, 1));

  if (rrc_container.size() > 0) {
    HANDLE_CODE(rrc_container.pack(bref));
  }
  HANDLE_CODE(srb_type.pack(bref));
  if (delivery_status_present) {
    HANDLE_CODE(pack_integer(bref, delivery_status, (uint16_t)0u, (uint16_t)4095u, true, true));
  }
  if (ie_exts_present) {
    HANDLE_CODE(ie_exts.pack(bref));
  }

  return OCUDUASN_SUCCESS;
}
OCUDUASN_CODE split_srb_rrc_transfer_s::unpack(cbit_ref& bref)
{
  bref.unpack(ext, 1);
  bool rrc_container_present;
  HANDLE_CODE(bref.unpack(rrc_container_present, 1));
  HANDLE_CODE(bref.unpack(delivery_status_present, 1));
  HANDLE_CODE(bref.unpack(ie_exts_present, 1));

  if (rrc_container_present) {
    HANDLE_CODE(rrc_container.unpack(bref));
  }
  HANDLE_CODE(srb_type.unpack(bref));
  if (delivery_status_present) {
    HANDLE_CODE(unpack_integer(delivery_status, bref, (uint16_t)0u, (uint16_t)4095u, true, true));
  }
  if (ie_exts_present) {
    HANDLE_CODE(ie_exts.unpack(bref));
  }

  return OCUDUASN_SUCCESS;
}
void split_srb_rrc_transfer_s::to_json(json_writer& j) const
{
  j.start_obj();
  if (rrc_container.size() > 0) {
    j.write_str("rrcContainer", rrc_container.to_string());
  }
  j.write_str("srbType", srb_type.to_string());
  if (delivery_status_present) {
    j.write_int("deliveryStatus", delivery_status);
  }
  if (ie_exts_present) {
    j.write_fieldname("iE-Extensions");
    ie_exts.to_json(j);
  }
  j.end_obj();
}

const char* split_srb_rrc_transfer_s::srb_type_opts::to_string() const
{
  static const char* names[] = {"srb1", "srb2"};
  return convert_enum_idx(names, 2, value, "split_srb_rrc_transfer_s::srb_type_e_");
}
uint8_t split_srb_rrc_transfer_s::srb_type_opts::to_number() const
{
  static const uint8_t numbers[] = {1, 2};
  return map_enum_number(numbers, 2, value, "split_srb_rrc_transfer_s::srb_type_e_");
}

