// RRCTransfer-IEs ::= OBJECT SET OF XNAP-PROTOCOL-IES
uint32_t rrc_transfer_ies_o::idx_to_id(uint32_t idx)
{
  static const uint32_t names[] = {23, 71, 74, 28, 147, 152, 352};
  return map_enum_number(names, 7, idx, "id");
}
bool rrc_transfer_ies_o::is_id_valid(const uint32_t& id)
{
  static const uint32_t names[] = {23, 71, 74, 28, 147, 152, 352};
  for (const auto& o : names) {
    if (o == id) {
      return true;
    }
  }
  return false;
}
crit_e rrc_transfer_ies_o::get_crit(const uint32_t& id)
{
  switch (id) {
    case 23:
      return crit_e::reject;
    case 71:
      return crit_e::reject;
    case 74:
      return crit_e::reject;
    case 28:
      return crit_e::reject;
    case 147:
      return crit_e::ignore;
    case 152:
      return crit_e::ignore;
    case 352:
      return crit_e::ignore;
    default:
      asn1::log_error("The id={} is not recognized", id);
  }
  return {};
}
rrc_transfer_ies_o::value_c rrc_transfer_ies_o::get_value(const uint32_t& id)
{
  value_c ret{};
  switch (id) {
    case 23:
      ret.set(value_c::types::m_ng_ra_nnode_ue_xn_ap_id);
      break;
    case 71:
      ret.set(value_c::types::s_ng_ra_nnode_ue_xn_ap_id);
      break;
    case 74:
      ret.set(value_c::types::split_srb_rrc_transfer);
      break;
    case 28:
      ret.set(value_c::types::ue_report_rrc_transfer);
      break;
    case 147:
      ret.set(value_c::types::fast_mcg_recovery_rrc_transfer_sn_to_mn);
      break;
    case 152:
      ret.set(value_c::types::fast_mcg_recovery_rrc_transfer_mn_to_sn);
      break;
    case 352:
      ret.set(value_c::types::sdt_srb_between_new_node_old_node);
      break;
    default:
      asn1::log_error("The id={} is not recognized", id);
  }
  return ret;
}
presence_e rrc_transfer_ies_o::get_presence(const uint32_t& id)
{
  switch (id) {
    case 23:
      return presence_e::mandatory;
    case 71:
      return presence_e::mandatory;
    case 74:
      return presence_e::optional;
    case 28:
      return presence_e::optional;
    case 147:
      return presence_e::optional;
    case 152:
      return presence_e::optional;
    case 352:
      return presence_e::optional;
    default:
      asn1::log_error("The id={} is not recognized", id);
  }
  return {};
}

// Value ::= OPEN TYPE
void rrc_transfer_ies_o::value_c::set(types::options e)
{
  type_ = e;
  switch (type_) {
    case types::m_ng_ra_nnode_ue_xn_ap_id:
      c = uint64_t{};
      break;
    case types::s_ng_ra_nnode_ue_xn_ap_id:
      c = uint64_t{};
      break;
    case types::split_srb_rrc_transfer:
      c = split_srb_rrc_transfer_s{};
      break;
    case types::ue_report_rrc_transfer:
      c = ue_report_rrc_transfer_s{};
      break;
    case types::fast_mcg_recovery_rrc_transfer_sn_to_mn:
      c = fast_mcg_recovery_rrc_transfer_s{};
      break;
    case types::fast_mcg_recovery_rrc_transfer_mn_to_sn:
      c = fast_mcg_recovery_rrc_transfer_s{};
      break;
    case types::sdt_srb_between_new_node_old_node:
      c = sdt_srb_between_new_node_old_node_s{};
      break;
    case types::nulltype:
      break;
    default:
      log_invalid_choice_id(type_, "rrc_transfer_ies_o::value_c");
  }
}
uint64_t& rrc_transfer_ies_o::value_c::m_ng_ra_nnode_ue_xn_ap_id()
{
  assert_choice_type(types::m_ng_ra_nnode_ue_xn_ap_id, type_, "Value");
  return c.get<uint64_t>();
}
