    case types::list_of_served_cells_e_utra:
      HANDLE_CODE(pack_dyn_seq_of(bref, c.get<served_cells_e_utra_l>(), 1, 16384, true));
      break;
    case types::crit_diagnostics:
      HANDLE_CODE(c.get<crit_diagnostics_s>().pack(bref));
      break;
    case types::amf_region_info:
      HANDLE_CODE(pack_dyn_seq_of(bref, c.get<amf_region_info_l>(), 1, 16, true));
      break;
    case types::interface_instance_ind:
      HANDLE_CODE(pack_integer(bref, c.get<uint16_t>(), (uint16_t)0u, (uint16_t)255u, true, true));
      break;
    case types::tnl_cfg_info:
      HANDLE_CODE(c.get<tnl_cfg_info_s>().pack(bref));
      break;
    case types::partial_list_ind_nr:
      HANDLE_CODE(c.get<partial_list_ind_e>().pack(bref));
      break;
    case types::cell_and_capacity_assist_info_nr:
      HANDLE_CODE(c.get<cell_and_capacity_assist_info_nr_s>().pack(bref));
      break;
    case types::partial_list_ind_eutra:
      HANDLE_CODE(c.get<partial_list_ind_e>().pack(bref));
      break;
    case types::cell_and_capacity_assist_info_eutra:
