void xn_u_address_ind_ies_o::value_c::to_json(json_writer& j) const
{
  j.start_obj();
  switch (type_) {
    case types::new_ng_ra_nnode_ue_xn_ap_id:
      j.write_int("INTEGER (0..4294967295)", c.get<uint64_t>());
      break;
    case types::old_ng_ra_nnode_ue_xn_ap_id:
      j.write_int("INTEGER (0..4294967295)", c.get<uint64_t>());
      break;
    case types::xn_u_address_infoper_pdu_session_list:
      j.start_array("XnUAddressInfoperPDUSession-List");
      for (const auto& e1 : c.get<xn_u_address_infoper_pdu_session_list_l>()) {
        e1.to_json(j);
      }
      j.end_array();
      break;
    case types::cho_mrdc_ind:
      j.write_str("CHO-MRDC-Indicator", c.get<cho_mrdc_ind_e>().to_string());
      break;
    case types::cho_mrdc_early_data_forwarding:
      j.write_str("CHO-MRDC-EarlyDataForwarding", "stop");
      break;
    case types::cp_c_data_forwarding_ind:
      j.write_str("CPC-DataForwarding-Indicator", c.get<cp_c_data_forwarding_ind_e>().to_string());
      break;
    default:
      log_invalid_choice_id(type_, "xn_u_address_ind_ies_o::value_c");
  }
  j.end_obj();
}
OCUDUASN_CODE xn_u_address_ind_ies_o::value_c::pack(bit_ref& bref) const
{
  varlength_field_pack_guard varlen_scope(bref, true);
  switch (type_) {
    case types::new_ng_ra_nnode_ue_xn_ap_id:
      HANDLE_CODE(pack_integer(bref, c.get<uint64_t>(), (uint64_t)0u, (uint64_t)4294967295u, false, true));
      break;
    case types::old_ng_ra_nnode_ue_xn_ap_id:
      HANDLE_CODE(pack_integer(bref, c.get<uint64_t>(), (uint64_t)0u, (uint64_t)4294967295u, false, true));
      break;
    case types::xn_u_address_infoper_pdu_session_list:
      HANDLE_CODE(pack_dyn_seq_of(bref, c.get<xn_u_address_infoper_pdu_session_list_l>(), 1, 256, true));
      break;
    case types::cho_mrdc_ind:
      HANDLE_CODE(c.get<cho_mrdc_ind_e>().pack(bref));
      break;
    case types::cho_mrdc_early_data_forwarding:
      HANDLE_CODE(c.get<cho_mrdc_early_data_forwarding_e>().pack(bref));
      break;
    case types::cp_c_data_forwarding_ind:
      HANDLE_CODE(c.get<cp_c_data_forwarding_ind_e>().pack(bref));
      break;
    default:
      log_invalid_choice_id(type_, "xn_u_address_ind_ies_o::value_c");
      return OCUDUASN_ERROR_ENCODE_FAIL;
  }
  return OCUDUASN_SUCCESS;
}
OCUDUASN_CODE xn_u_address_ind_ies_o::value_c::unpack(cbit_ref& bref)
{
  varlength_field_unpack_guard varlen_scope(bref, true);
  switch (type_) {
    case types::new_ng_ra_nnode_ue_xn_ap_id:
      HANDLE_CODE(unpack_integer(c.get<uint64_t>(), bref, (uint64_t)0u, (uint64_t)4294967295u, false, true));
      break;
    case types::old_ng_ra_nnode_ue_xn_ap_id:
      HANDLE_CODE(unpack_integer(c.get<uint64_t>(), bref, (uint64_t)0u, (uint64_t)4294967295u, false, true));
      break;
    case types::xn_u_address_infoper_pdu_session_list:
      HANDLE_CODE(unpack_dyn_seq_of(c.get<xn_u_address_infoper_pdu_session_list_l>(), bref, 1, 256, true));
      break;
    case types::cho_mrdc_ind:
      HANDLE_CODE(c.get<cho_mrdc_ind_e>().unpack(bref));
      break;
    case types::cho_mrdc_early_data_forwarding:
      HANDLE_CODE(c.get<cho_mrdc_early_data_forwarding_e>().unpack(bref));
      break;
    case types::cp_c_data_forwarding_ind:
      HANDLE_CODE(c.get<cp_c_data_forwarding_ind_e>().unpack(bref));
      break;
    default:
      log_invalid_choice_id(type_, "xn_u_address_ind_ies_o::value_c");
      return OCUDUASN_ERROR_DECODE_FAIL;
  }
  return OCUDUASN_SUCCESS;
}

